#include <bits/stdc++.h>
using namespace std;
int n;
bool szs(int a) {
	int i=5;
	bool s=1;
	if(a==2||a==3)return 1;
	if(a%2==0||a%3==0) {
		return 0;
	}
	while(i*i<=a) {
		if(a%i==0) {
			return 0;
		}
		i+=2;
	}
	return 1;
}
int main() {
	cin>>n;
	//ios::sync_with_stdio(false);
	for(int i=4; i<=n; i+=2) {
		printf("%d=",i);
		for(int j=2; j<=i/2; j++) {
			bool has=0;
			for(int y=2; y<=i-j; y++) {
				if(szs(j)&&szs(y)&&j+y==i) {
					has=1;
					// cout<<j<<"+"<<y;
					printf("%d+%d",j,y);
					break;
				}
			}
			if(has==1) {
				break;
			}
		}
		printf("\n");
	}
	return 0;
}
